Can you check if the following smart contract written in Rust contains a vulnerability? ```pub fn update_indexes(&mut self, clock: &Clock) -> MangoResult<()> {





        let curr_ts = clock.unix_timestamp as u64;

        for i in 0..NUM_TOKENS {
            let interest_rate = self.get_interest_rate(i);
            let index: &mut MangoIndex = &mut self.indexes[i];
            if index.last_update == curr_ts || self.total_deposits[i] == ZERO_U64F64 {

                continue;
            }


            let native_deposits: U64F64 = self.total_deposits[i].checked_mul(index.deposit).unwrap();
            let native_borrows: U64F64 = self.total_borrows[i].checked_mul(index.borrow).unwrap();
            check_default!(native_borrows <= native_deposits + EPSILON)?;  

            let utilization = native_borrows.checked_div(native_deposits).unwrap();
            let borrow_interest = interest_rate
                .checked_mul(U64F64::from_num(curr_ts - index.last_update)).unwrap();

            let deposit_interest = borrow_interest
                .checked_mul(utilization).unwrap();

            index.last_update = curr_ts;
            index.borrow = index.borrow.checked_mul(borrow_interest).unwrap()
                .checked_add(index.borrow).unwrap();

            index.deposit = index.deposit.checked_mul(deposit_interest).unwrap()
                .checked_add(index.deposit).unwrap();
        }
        Ok(())
    }```.

Can you check if the following smart contract written in Rust contains a vulnerability? ```fn invoke_cancel_orders<'a>(
    open_orders_acc: &AccountInfo<'a>,
    dex_prog_acc: &AccountInfo<'a>,
    spot_market_acc: &AccountInfo<'a>,
    bids_acc: &AccountInfo<'a>,
    asks_acc: &AccountInfo<'a>,
    signer_acc: &AccountInfo<'a>,
    dex_event_queue_acc: &AccountInfo<'a>,
    signers_seeds: &[&[&[u8]]],

    mut limit: u8
) -> MangoResult<()> {
    let mut cancels = vec![];
    {
        let open_orders = load_open_orders(open_orders_acc)?;

        let market = load_market_state(spot_market_acc, dex_prog_acc.key)?;
        let bids = load_bids_mut(&market, bids_acc)?;
        let asks = load_asks_mut(&market, asks_acc)?;

        limit = min(limit, open_orders.free_slot_bits.count_zeros() as u8);
        if limit == 0 {
            return Ok(());
        }
        for j in 0..128 {
            let slot_mask = 1u128 << j;
            if open_orders.free_slot_bits & slot_mask != 0 {  
                continue;
            }
            let order_id = open_orders.orders[j];

            let side = if open_orders.is_bid_bits & slot_mask != 0 {
                match bids.find_by_key(order_id) {
                    None => { continue }
                    Some(_) => serum_dex::matching::Side::Bid
                }
            } else {
                match asks.find_by_key(order_id) {
                    None => { continue }
                    Some(_) => serum_dex::matching::Side::Ask
                }
            };

            let cancel_instruction = serum_dex::instruction::CancelOrderInstructionV2 { side, order_id };

            cancels.push(cancel_instruction);

            limit -= 1;
            if limit == 0 {
                break;
            }
        }
    }

    let mut instruction = Instruction {
        program_id: *dex_prog_acc.key,
        data: vec![],
        accounts: vec![
            AccountMeta::new(*spot_market_acc.key, false),
            AccountMeta::new(*bids_acc.key, false),
            AccountMeta::new(*asks_acc.key, false),
            AccountMeta::new(*open_orders_acc.key, false),
            AccountMeta::new_readonly(*signer_acc.key, true),
            AccountMeta::new(*dex_event_queue_acc.key, false),
        ],
    };

    let account_infos = [
        dex_prog_acc.clone(),
        spot_market_acc.clone(),
        bids_acc.clone(),
        asks_acc.clone(),
        open_orders_acc.clone(),
        signer_acc.clone(),
        dex_event_queue_acc.clone()
    ];

    for cancel in cancels.iter() {
        let cancel_instruction = serum_dex::instruction::MarketInstruction::CancelOrderV2(cancel.clone());
        instruction.data = cancel_instruction.pack();
        solana_program::program::invoke_signed(&instruction, &account_infos, signers_seeds)?;
    }

    Ok(())
}```.

